.tag-illusion { background: var(--red-bg); color: var(--red); }

/* ===== GIF Container (shared across demo, temporal, generator) ===== */
.gif-container {
    width: 100%;
    min-height: 200px;
    max-height: 400px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #000;
    position: relative;
}
.gif-container img {
    max-width: 100%;
    max-height: 400px;
    object-fit: contain;
}
.gif-container .gif-loading { color: var(--muted); font-size: 0.9rem; }
.gif-container .gif-error {
    color: var(--muted);
    font-size: 0.9rem;
    text-align: center;
    padding: 2rem;
}
.gif-container .gif-error a { color: var(--accent); text-decoration: none; }
.gif-container .gif-error a:hover { text-decoration: underline; }

/* ===== Challenge Card (shared across demo, temporal) ===== */
.challenge {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 12px;
    overflow: hidden;
    margin-bottom: 1.5rem;
}
.challenge-header {
    padding: 1rem 1.5rem;
    border-bottom: 1px solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: center;
}
.challenge-header .label { font-size: 0.85rem; color: var(--muted); }
.challenge-header .number { font-weight: 700; color: var(--accent); }
.challenge-prompt {
    padding: 1.25rem 1.5rem;
    border-top: 1px solid var(--border);
}
.challenge-prompt .prompt-text {
    font-size: 0.95rem;
    font-weight: 600;
    margin-bottom: 0.4rem;
}
.challenge-prompt .prompt-hint { font-size: 0.8rem; color: var(--muted); }

/* ===== Progress Bar (shared across demo, temporal) ===== */
.progress-container {
    max-width: 700px;
    margin: 0 auto;
    padding: 1.5rem 1.5rem 0;
}
.progress-bar-bg {
    width: 100%;
    height: 6px;
    background: var(--border);
    border-radius: 3px;
    overflow: hidden;
}
.progress-bar-fill {
    height: 100%;
    background: var(--accent);
    border-radius: 3px;
    transition: width 0.4s ease;
}
.progress-label {
    display: flex;
    justify-content: space-between;
    margin-top: 0.5rem;
    font-size: 0.8rem;
    color: var(--muted);
}

/* ===== Insight Box (shared across analysis, simulator) ===== */
.insight-box {
    background: var(--surface);
    border: 1px solid var(--border);
    border-left: 4px solid var(--accent);
    border-radius: 0 8px 8px 0;
    padding: 1.25rem;
    margin: 1.5rem 0;
}
.insight-box h4 {
    font-size: 0.9rem;
    margin-bottom: 0.4rem;
    color: var(--accent);
}
.insight-box p { font-size: 0.85rem; color: var(--muted); }

/* ===== Two Column Layout ===== */
.two-col {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1.5rem;
}

/* ===== Fade-in Animation ===== */
@keyframes fadeIn {
    from { opacity: 0; transform: translateY(8px); }
    to { opacity: 1; transform: translateY(0); }
}

/* ===== Footer ===== */
footer {
    margin-top: 3rem;
    padding-top: 1.5rem;
    border-top: 1px solid var(--border);
    color: var(--muted);
    font-size: 0.85rem;
    text-align: center;
}
footer a { color: var(--accent); text-decoration: none; }
footer a:hover { text-decoration: underline; }

/* ===== Utilities ===== */
.hidden { display: none !important; }
.skip-link {
    color: var(--muted);
    font-size: 0.8rem;
    cursor: pointer;
    background: none;
    border: none;
    text-decoration: underline;
    font-family: inherit;
}
.skip-link:hover { color: var(--text); }

/* ===== Responsive Base ===== */
@media (max-width: 768px) {
    .two-col { grid-template-columns: 1fr; }
}
@media (max-width: 600px) {
    .header h1 { font-size: 1.5rem; }
    .container { padding: 1rem; }
}

